mapper.select:
SELECT

    DEV_NAME as devName,


    any(DEV_NAME) as devName,

TIME as time,


        IO_STAT as ioStat, RD_STAT as rdStat, WR_STAT as wrStat, round(RD_REQ/${duration}) AS rdReq, round(WR_REQ/${duration}) AS wrReq, RD_LATENCY as rdLatency, WR_LATENCY as wrLatency


        SUM(IO_STAT) as ioStat, SUM(RD_STAT) as rdStat, SUM(WR_STAT) as wrStat, round(SUM(RD_REQ/${duration})) AS rdReq, round(SUM(WR_REQ/${duration})) AS wrReq


FROM TBL_STORAGE_MULTIPATH_IO_STAT  WHERE TIME BETWEEN ${startTime} AND ${endTime} AND POOL_NAME =#{poolName}

    AND HOST_ID=${hostId}


    AND CLUSTER_ID=${clusterId}


    AND DEV_NAME =#{currentDisk}


    AND POOL_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))


    GROUP BY POOL_NAME,TIME

ORDER BY TIME ASC
